const TOTAL = SUBJECTS.reduce((s, sub) => s + sub.okruhy.length, 0);
const DONE = SUBJECTS.reduce((s, sub) => s + sub.okruhy.filter(o => o.status === "done").length, 0);

/* ════════════════════════════════════════════════════════
   PRIMITIVES
   ════════════════════════════════════════════════════════ */
function Def({ children, color }) {
  const t = useTheme();
  const c = color || t.accent;
  return <div style={{ background: t.surfaceMuted, border: `1px solid ${t.borderSoft}`, borderLeft: `3px solid ${c}`, borderRadius: RADIUS.md, padding: "14px 16px", marginBottom: 12, fontSize: 15.5, color: t.text, lineHeight: 1.6, fontFamily: fontSans }}>{children}</div>;
}
function Tag({ children, color }) {
  const t = useTheme();
  return <div style={{ fontSize: 12.5, fontWeight: 600, color: color || t.textMuted, fontFamily: fontMono, textTransform: "uppercase", letterSpacing: "1.6px", marginTop: 14, marginBottom: 6 }}>{children}</div>;
}
function Bullet({ items, color }) {
  const t = useTheme();
  const c = color || t.accent;
  return <div style={{ display: "flex", flexDirection: "column", gap: 4, marginTop: 4 }}>{items.map((item, i) => (
    <div key={i} style={{ display: "flex", gap: 10, fontSize: 15, color: t.text, lineHeight: 1.55, fontFamily: fontSans }}>
      <span style={{ color: c, flexShrink: 0, fontFamily: fontMono }}>›</span><span dangerouslySetInnerHTML={{ __html: item }} />
    </div>
  ))}</div>;
}

/* ExamAlert — vizuální upozornění na tažené otázky uvnitř studyssekce */
function ExamAlert({ komise, what, color }) {
  const t = useTheme();
  const c = color || VSE.danger;
  return (
    <div style={{
      background: t.surfaceMuted,
      border: `1px solid ${t.borderSoft}`,
      borderLeft: `4px solid ${c}`,
      borderRadius: RADIUS.md,
      padding: "12px 14px",
      marginTop: 14,
      marginBottom: 10,
      fontSize: 14.5,
      fontFamily: fontSans,
      color: t.text,
      lineHeight: 1.55
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
        <span style={{ fontSize: 13, color: c }}>⚠️</span>
        <span style={{ fontSize: 12, fontFamily: fontMono, color: c, fontWeight: 700, letterSpacing: "1.4px", textTransform: "uppercase" }}>Tažená — {komise}</span>
      </div>
      <div dangerouslySetInnerHTML={{ __html: what }} />
    </div>
  );
}

/* ════════════════════════════════════════════════════════
   RESPONSIVE HELPERS — pro mobile-friendly layout
   ════════════════════════════════════════════════════════ */
function useIsMobile() {
  const [isMobile, setIsMobile] = useState(typeof window !== "undefined" ? window.innerWidth < 720 : false);
  useEffect(() => {
    const onResize = () => setIsMobile(window.innerWidth < 720);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);
  return isMobile;
}

function ResponsiveGrid({ children, cols2, cols3, style }) {
  const isMobile = useIsMobile();
  const cols = isMobile ? 1 : (cols3 ? 3 : (cols2 ? 2 : 1));
  return (
    <div style={{ display: "grid", gridTemplateColumns: `repeat(${cols}, 1fr)`, gap: 10, marginTop: 8, ...style }}>
      {children}
    </div>
  );
}

function ResponsiveSVG({ children, viewBox = "0 0 600 400", maxHeight = 400, style }) {
  return (
    <div style={{ width: "100%", maxWidth: "100%", overflow: "hidden", margin: "8px 0", ...style }}>
      <svg viewBox={viewBox} preserveAspectRatio="xMidYMid meet" style={{ width: "100%", height: "auto", maxHeight, display: "block" }}>
        {children}
      </svg>
    </div>
  );
}

function PlusMinus({ type, items }) {
  const t = useTheme();
  const isP = type === "plus"; const col = isP ? VSE.success : VSE.danger;
  return (
    <div style={{ background: t.surfaceMuted, border: `1px solid ${t.borderSoft}`, borderLeft: `3px solid ${col}`, borderRadius: RADIUS.md, padding: 14 }}>
      <div style={{ fontSize: 12.5, fontWeight: 600, color: col, fontFamily: fontMono, marginBottom: 8, letterSpacing: "1.6px", textTransform: "uppercase" }}>{isP ? "Ano · plusy" : "Ne · mínusy"}</div>
      {items.map((it, i) => <div key={i} style={{ fontSize: 14.5, color: t.text, lineHeight: 1.5, fontFamily: fontSans, marginBottom: 4, paddingLeft: 12, borderLeft: `1px solid ${t.borderSoft}` }} dangerouslySetInnerHTML={{ __html: it }} />)}
    </div>
  );
}
function ModelCard({ name, color, items }) {
  const t = useTheme();
  const c = color || t.accent;
  return (
    <div style={{ background: t.surface, border: `1px solid ${t.borderSoft}`, borderRadius: RADIUS.md, padding: "14px 16px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
        <div style={{ width: 6, height: 6, borderRadius: 99, background: c }} />
        <div style={{ fontSize: 15, fontWeight: 600, color: t.text, fontFamily: fontSans, letterSpacing: "-0.01em" }}>{name}</div>
      </div>
      {items.map((it, i) => <div key={i} style={{ display: "flex", gap: 8, fontSize: 14.5, color: t.textMuted, lineHeight: 1.55, fontFamily: fontSans, marginBottom: 3 }}><span style={{ color: c, flexShrink: 0 }}>–</span><span dangerouslySetInnerHTML={{ __html: it }} /></div>)}
    </div>
  );
}
function ExamQ({ komise, otazka, pozn }) {
  const t = useTheme();
  return (
    <div style={{ background: t.surfaceMuted, border: `1px solid ${t.borderSoft}`, borderRadius: RADIUS.md, padding: "14px 16px", marginBottom: 8, marginTop: 4 }}>
      <div style={{ fontSize: 12.5, color: t.textSubtle, fontFamily: fontMono, marginBottom: 6, letterSpacing: "1.6px", textTransform: "uppercase", fontWeight: 600 }}>{komise}</div>
      <div style={{ fontSize: 15.5, color: t.text, fontWeight: 500, fontFamily: fontSans, marginBottom: 6, lineHeight: 1.45 }}>„<span dangerouslySetInnerHTML={{ __html: otazka }} />”</div>
      <div style={{ fontSize: 14.5, color: t.cta, fontFamily: fontItalic, fontStyle: "italic" }}>→ <span dangerouslySetInnerHTML={{ __html: pozn }} /></div>
    </div>
  );
}

function Difficulty({ sloz, roz, freq }) {
  const t = useTheme();
  const P = ({ f, col }) => <span style={{ width: 6, height: 6, borderRadius: 99, background: f ? col : t.borderSoft, display: "inline-block" }} />;
  const items = [
    { lbl: "Složitost", val: sloz, col: sloz === 3 ? t.cta : sloz === 2 ? VSE.warning : t.accent },
    { lbl: "Rozsah", val: roz, col: roz === 3 ? t.cta : roz === 2 ? VSE.warning : t.accent },
    { lbl: "Frekvence", val: freq, col: freq === 3 ? t.cta : freq === 2 ? VSE.warning : t.accent },
  ];
  return (
    <div style={{ display: "flex", gap: 10, justifyContent: "center", padding: "10px 0", flexWrap: "wrap" }}>
      {items.map((x, i) => (
        <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, background: t.surface, border: `1px solid ${t.borderSoft}`, borderRadius: RADIUS.pill, padding: "7px 14px" }}>
          <span style={{ fontSize: 12.5, color: t.textMuted, fontFamily: fontMono, fontWeight: 600, textTransform: "uppercase", letterSpacing: "1.4px" }}>{x.lbl}</span>
          <div style={{ display: "flex", gap: 3 }}>{[1,2,3].map(i => <P key={i} f={i <= x.val} col={x.col} />)}</div>
        </div>
      ))}
    </div>
  );
}

function ChecklistGeneric({ items }) {
  const t = useTheme();
  const [checked, setChecked] = useState(new Set());
  const toggle = (id) => setChecked(p => { const n = new Set(p); n.has(id) ? n.delete(id) : n.add(id); return n; });
  const pct = Math.round((checked.size / items.length) * 100);
  return (
    <div style={{ ...cardStyle(t), padding: 20, marginBottom: 4 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 12 }}>
        <span style={{ fontSize: 13, fontFamily: fontMono, color: t.textMuted, fontWeight: 600, letterSpacing: "1.6px", textTransform: "uppercase" }}>Checklist přípravy</span>
        <span style={{ fontSize: 14.5, fontFamily: fontMono, color: pct === 100 ? VSE.success : t.accent, fontWeight: 600 }}>{pct}%</span>
      </div>
      <div style={{ height: 4, background: t.borderSoft, borderRadius: 99, marginBottom: 14, overflow: "hidden" }}>
        <div style={{ height: "100%", width: `${pct}%`, background: pct === 100 ? VSE.success : t.accent, borderRadius: 99, transition: "width 0.4s cubic-bezier(0.4,0,0.2,1)" }} />
      </div>
      {items.map((it) => (
        <div key={it.id} onClick={() => toggle(it.id)} style={{ display: "flex", alignItems: "center", gap: 12, padding: "9px 10px", borderRadius: RADIUS.sm, cursor: "pointer", marginBottom: 2, background: checked.has(it.id) ? t.surfaceMuted : "transparent", transition: "background 0.2s" }}>
          <div style={{ width: 18, height: 18, borderRadius: 5, border: `1.5px solid ${checked.has(it.id) ? VSE.success : t.borderStrong}`, background: checked.has(it.id) ? VSE.success : "transparent", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontSize: 13, color: "#fff", transition: "all 0.2s" }}>
            {checked.has(it.id) && "✓"}
          </div>
          <span style={{ fontSize: 15.5, fontFamily: fontSans, color: checked.has(it.id) ? t.textMuted : t.text, textDecoration: checked.has(it.id) ? "line-through" : "none", transition: "all 0.2s" }}>{it.label}</span>
        </div>
      ))}
    </div>
  );
}

function Section({ s, isOpen, onToggle, subjectId, okruhN, subjectLabel }) {
  const t = useTheme();
  const showWatch = subjectId && okruhN;
  const accent = s.color || t.accent;
  return (
    <div style={{ marginBottom: 4 }}>
      <div style={{
        background: isOpen ? t.surface : t.surface,
        border: `1px solid ${isOpen ? t.borderStrong : t.borderSoft}`,
        borderRadius: RADIUS.lg, padding: isOpen ? "20px 22px" : "14px 18px",
        transition: "all 0.25s cubic-bezier(0.4,0,0.2,1)",
        boxShadow: isOpen ? t.shadow : "none",
        position: "relative", overflow: "hidden",
      }}>
        {isOpen && <div style={{ position: "absolute", top: 0, left: 0, width: 3, height: "100%", background: accent }} />}
        <div onClick={onToggle} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12, cursor: "pointer", userSelect: "none" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 14, flex: 1, minWidth: 0 }}>
            <Icon name={s.emoji} size={20} color={isOpen ? accent : t.textMuted} />
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 15, fontWeight: 600, color: t.text, fontFamily: fontSans, letterSpacing: "-0.015em" }}>{s.title}</div>
              {s.subtitle && <div style={{ fontSize: 14.5, color: t.textMuted, fontFamily: fontSans, marginTop: 3 }}>{s.subtitle}</div>}
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            {showWatch && isOpen && <WatchToggleButton subjectId={subjectId} okruhN={okruhN} sectionId={s.id} sectionTitle={s.title} subjectLabel={subjectLabel} />}
            <span style={{ color: t.textMuted, fontSize: 14, fontFamily: fontMono, transition: "transform 0.3s", transform: isOpen ? "rotate(180deg)" : "rotate(0deg)" }}>▾</span>
          </div>
        </div>
        {isOpen && <div style={{ marginTop: 18, userSelect: "text" }}>{s.content}</div>}
      </div>
    </div>
  );
}

function FlashcardsTab({ data }) {
  const t = useTheme();
  const [idx, setIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  // Klíč pro localStorage = hash z první otázky (krátký a stabilní)
  const storageKey = `nabombuj_flashcards_${(data[0]?.term || "").substring(0, 30).replace(/\s/g, "_")}`;
  const [known, setKnown] = useState(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      return saved ? new Set(JSON.parse(saved)) : new Set();
    } catch { return new Set(); }
  });
  const card = data[idx];
  const mark = (know) => {
    setKnown(p => {
      const n = new Set(p);
      if (know) n.add(idx);
      else n.delete(idx);
      try { localStorage.setItem(storageKey, JSON.stringify(Array.from(n))); } catch {}
      return n;
    });
    setFlipped(false);
    setIdx((idx + 1) % data.length);
    // Streak activity
    try { recordActivity(); window.dispatchEvent(new Event("streak-updated")); } catch {}
  };
  const resetProgress = () => {
    setKnown(new Set());
    setIdx(0);
    setFlipped(false);
    try { localStorage.removeItem(storageKey); } catch {}
  };
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <span style={{ fontSize: 14, fontFamily: fontMono, color: t.textMuted }}>{idx + 1}/{data.length}</span>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <span style={{ fontSize: 14, fontFamily: fontMono, color: VSE.success, fontWeight: 700 }}>Umím: {known.size}/{data.length}</span>
          {known.size > 0 && (
            <button onClick={resetProgress} title="Resetovat pokrok kartiček" style={{
              padding: "4px 10px", borderRadius: 8, border: `1px solid ${t.border}`,
              background: "transparent", color: t.textMuted, cursor: "pointer",
              fontSize: 12.5, fontFamily: fontMono, letterSpacing: "0.5px",
            }}>↻ RESET</button>
          )}
        </div>
      </div>
      <div style={{ display: "flex", gap: 3, marginBottom: 16 }}>
        {data.map((_, i) => <div key={i} style={{ flex: 1, height: 3, borderRadius: 99, background: i === idx ? t.accent : known.has(i) ? VSE.success : t.borderSoft, transition: "background 0.3s" }} />)}
      </div>
      <div onClick={() => setFlipped(!flipped)} style={{
        ...cardStyle(t),
        minHeight: 240, padding: 36,
        cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center",
        transition: "all 0.3s cubic-bezier(0.4,0,0.2,1)",
      }}>
        <div style={{ fontSize: 12.5, fontFamily: fontMono, color: t.textMuted, marginBottom: 14, letterSpacing: "1.6px", fontWeight: 600, textTransform: "uppercase" }}>{card.tag}</div>
        {!flipped ? (
          <><div style={{ fontSize: 28, fontWeight: 500, color: t.text, fontFamily: fontSans, marginBottom: 16, letterSpacing: "-0.02em", lineHeight: 1.2 }}>{card.term}</div>
          <div style={{ fontSize: 14, color: t.textMuted, fontFamily: fontMono, letterSpacing: "1.2px", textTransform: "uppercase" }}>klikni pro odpověď</div></>
        ) : (
          <><div style={{ fontSize: 15.5, fontWeight: 600, color: t.accent, fontFamily: fontSans, marginBottom: 12, letterSpacing: "-0.01em" }}>{card.term}</div>
          <div style={{ fontSize: 15, color: t.text, fontFamily: fontSans, lineHeight: 1.65, textWrap: "pretty" }}>{card.def}</div></>
        )}
      </div>
      {flipped && (
        <div style={{ display: "flex", gap: 10, marginTop: 14 }}>
          <button onClick={() => mark(false)} style={{ flex: 1, padding: 14, borderRadius: RADIUS.md, border: `1px solid ${t.border}`, background: t.surface, color: t.textMuted, fontSize: 15, fontWeight: 500, fontFamily: fontSans, cursor: "pointer", transition: "all 0.2s" }}>Neumím</button>
          <button onClick={() => mark(true)} style={{ flex: 1, padding: 14, borderRadius: RADIUS.md, border: `1px solid ${t.accent}`, background: t.accent, color: BOMBIK.paper, fontSize: 15, fontWeight: 600, fontFamily: fontSans, cursor: "pointer", transition: "all 0.2s" }}>Umím ✓</button>
        </div>
      )}
    </div>
  );
}

function QuizTab({ data }) {
  const t = useTheme();
  const storageKey = `nabombuj_quiz_${(data[0]?.q || "").substring(0, 30).replace(/\s/g, "_")}`;
  const [current, setCurrent] = useState(0);
  const [answers, setAnswers] = useState({});
  const [showResult, setShowResult] = useState(false);
  const [selected, setSelected] = useState(null);
  const [bestScore, setBestScore] = useState(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      return saved ? JSON.parse(saved) : null;
    } catch { return null; }
  });
  const handleSelect = (i) => {
    if (answers[current] !== undefined) return;
    setSelected(i);
    setAnswers(p => ({ ...p, [current]: i }));
    // Streak activity
    try { recordActivity(); window.dispatchEvent(new Event("streak-updated")); } catch {}
  };
  const next = () => {
    if (current < data.length - 1) { setCurrent(current + 1); setSelected(null); }
    else {
      setShowResult(true);
      // Ulož best score
      const finalScore = Object.entries({ ...answers }).filter(([k, v]) => data[k].correct === v).length;
      if (!bestScore || finalScore > bestScore.score) {
        const newBest = { score: finalScore, total: data.length, date: new Date().toISOString().split("T")[0] };
        setBestScore(newBest);
        try { localStorage.setItem(storageKey, JSON.stringify(newBest)); } catch {}
      }
    }
  };
  const reset = () => { setCurrent(0); setAnswers({}); setShowResult(false); setSelected(null); };
  const score = Object.entries(answers).filter(([k, v]) => data[k].correct === v).length;

  if (showResult) {
    const pct = Math.round((score / data.length) * 100);
    return (
      <div style={{ textAlign: "center", padding: 20 }}>
        <div style={{ marginBottom: 16 }}><Icon name={pct >= 80 ? "trophy" : pct >= 50 ? "muscle" : "book"} size={48} color={pct >= 80 ? VSE.success : pct >= 50 ? t.cta : t.textMuted} /></div>
        <div style={{ fontSize: 56, fontWeight: 600, fontFamily: fontSans, color: t.text, marginBottom: 6, letterSpacing: "-0.03em", lineHeight: 1 }}>{score}<span style={{ color: t.textSubtle, fontWeight: 400 }}>/{data.length}</span></div>
        <div style={{ fontSize: 16, color: t.text, marginBottom: 4, fontStyle: "italic", fontFamily: fontItalic }}>{pct >= 80 ? "Tohle zvládáš." : pct >= 50 ? "Dobrý základ, doplň mezery." : "Projít materiály znovu."}</div>
        <div style={{ fontSize: 13, color: t.textMuted, fontFamily: fontMono, marginBottom: 28, letterSpacing: "1.6px", textTransform: "uppercase" }}>{pct}% správně</div>
        <div style={{ textAlign: "left", marginBottom: 20 }}>
          {data.map((q, i) => {
            const isCorrect = answers[i] === q.correct;
            return (
              <div key={i} style={{ padding: "12px 14px", marginBottom: 6, borderRadius: RADIUS.sm, background: t.surfaceMuted, border: `1px solid ${t.borderSoft}`, borderLeft: `3px solid ${isCorrect ? VSE.success : t.cta}` }}>
                <div style={{ fontSize: 14.5, color: t.text, fontFamily: fontSans, lineHeight: 1.45 }}>{i + 1}. {q.q}</div>
                {!isCorrect && <div style={{ fontSize: 14.5, color: VSE.success, fontFamily: fontSans, marginTop: 4, fontWeight: 500 }}>Správně: {q.opts[q.correct]}</div>}
              </div>
            );
          })}
        </div>
        <button onClick={reset} style={{ padding: "12px 28px", borderRadius: RADIUS.pill, border: `1px solid ${t.border}`, background: t.surface, color: t.text, fontSize: 15, fontWeight: 500, fontFamily: fontSans, cursor: "pointer" }}>Zkusit znovu</button>
      </div>
    );
  }

  const q = data[current];
  const answered = answers[current] !== undefined;
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 12, alignItems: "center" }}>
        <span style={{ fontSize: 14, fontFamily: fontMono, color: t.textMuted }}>Otázka {current + 1}/{data.length}</span>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          {bestScore && (
            <span style={{ fontSize: 13, fontFamily: fontMono, color: VSE.warning, fontWeight: 700, padding: "3px 8px", borderRadius: 6, background: `${VSE.warning}10`, border: `1px solid ${VSE.warning}30` }}>
              ★ {bestScore.score}/{bestScore.total}
            </span>
          )}
          <span style={{ fontSize: 14, fontFamily: fontMono, color: VSE.success, fontWeight: 700 }}>{score} správně</span>
        </div>
      </div>
      <div style={{ display: "flex", gap: 3, marginBottom: 22 }}>
        {data.map((_, i) => <div key={i} style={{ flex: 1, height: 3, borderRadius: 99, background: i === current ? t.accent : answers[i] !== undefined ? (data[i].correct === answers[i] ? VSE.success : t.cta) : t.borderSoft }} />)}
      </div>
      <div style={{ fontSize: 19, fontWeight: 500, color: t.text, fontFamily: fontSans, lineHeight: 1.4, marginBottom: 22, letterSpacing: "-0.02em", textWrap: "pretty" }}>{q.q}</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
        {q.opts.map((opt, i) => {
          let bg = t.surface; let border = t.borderSoft; let tc = t.text;
          if (answered) {
            if (i === q.correct) { bg = t.surfaceMuted; border = VSE.success; tc = t.text; }
            else if (i === answers[current] && i !== q.correct) { bg = t.surfaceMuted; border = t.cta; tc = t.cta; }
            else { tc = t.textMuted; }
          } else if (selected === i) { bg = t.surfaceMuted; border = t.accent; }
          return (
            <div key={i} onClick={() => handleSelect(i)} style={{
              padding: "14px 16px", borderRadius: RADIUS.md, border: `1.5px solid ${border}`,
              background: bg,
              cursor: answered ? "default" : "pointer", transition: "all 0.2s", display: "flex", alignItems: "center", gap: 12,
            }}>
              <div style={{ width: 24, height: 24, borderRadius: 7, border: `1.5px solid ${answered ? (i === q.correct ? VSE.success : i === answers[current] ? t.cta : t.borderSoft) : t.border}`, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontSize: 13.5, fontWeight: 600, color: answered && i === q.correct ? BOMBIK.paper : tc, fontFamily: fontMono, background: answered && i === q.correct ? VSE.success : "transparent" }}>
                {answered ? (i === q.correct ? "✓" : i === answers[current] ? "✗" : String.fromCharCode(65 + i)) : String.fromCharCode(65 + i)}
              </div>
              <span style={{ fontSize: 14.5, color: tc, fontFamily: fontSans, textWrap: "pretty" }}>{opt}</span>
            </div>
          );
        })}
      </div>
      {answered && (
        <button onClick={next} style={{ marginTop: 18, width: "100%", padding: 14, borderRadius: RADIUS.md, border: "none", background: t.text, color: t.bg, fontSize: 15.5, fontWeight: 600, fontFamily: fontSans, cursor: "pointer", letterSpacing: "-0.01em" }}>
          {current < data.length - 1 ? "Další otázka →" : "Zobrazit výsledek"}
        </button>
      )}
    </div>
  );
}

function OrgSvg({ type, color }) {
  const c = color || VSE.primary;
  if (type === "ameby") return (
    <svg viewBox="0 0 100 60" style={{ width: 80, height: 48 }}>
      <ellipse cx="25" cy="28" rx="18" ry="14" fill={`${c}25`} stroke={c} strokeWidth="1"><animate attributeName="rx" values="18;21;18" dur="3s" repeatCount="indefinite"/></ellipse>
      <ellipse cx="65" cy="22" rx="14" ry="12" fill={`${c}20`} stroke={c} strokeWidth="1"><animate attributeName="ry" values="12;15;12" dur="2.5s" repeatCount="indefinite"/></ellipse>
      <ellipse cx="75" cy="42" rx="16" ry="12" fill={`${c}18`} stroke={c} strokeWidth="1"/>
      {[[18,24],[32,32],[58,18],[72,26],[68,40],[82,44]].map(([x,y],i) => <circle key={i} cx={x} cy={y} r="2.5" fill={c} opacity=".7"/>)}
    </svg>);
  if (type === "holo") return (
    <svg viewBox="0 0 100 60" style={{ width: 80, height: 48 }}>
      <circle cx="50" cy="30" r="22" fill="none" stroke={`${c}40`} strokeWidth="1" strokeDasharray="3 2"/>
      <circle cx="50" cy="30" r="12" fill="none" stroke={`${c}55`} strokeWidth="1" strokeDasharray="3 2"/>
      {[0,72,144,216,288].map((a,i)=>{const r=22;const rad=a*Math.PI/180;return <circle key={i} cx={50+r*Math.cos(rad)} cy={30+r*Math.sin(rad)} r="3" fill={c} opacity=".8"/>})}
    </svg>);
  if (type === "spag") return (
    <svg viewBox="0 0 100 60" style={{ width: 80, height: 48 }}>
      <path d="M10,15 Q30,50 55,20 Q75,0 95,35" fill="none" stroke={`${c}45`} strokeWidth="1.5"/>
      <path d="M8,40 Q25,10 50,42 Q70,55 95,22" fill="none" stroke={`${c}40`} strokeWidth="1.5"/>
      {[[10,15],[55,20],[95,35],[8,40],[50,42],[95,22]].map(([x,y],i) => <circle key={i} cx={x} cy={y} r="3" fill={c} opacity=".7"/>)}
    </svg>);
  if (type === "net") return (
    <svg viewBox="0 0 100 60" style={{ width: 80, height: 48 }}>
      {[[20,15],[50,15],[80,15],[35,35],[65,35],[20,50],[50,50],[80,50]].map(([x,y],i) => <circle key={i} cx={x} cy={y} r="3" fill={c} opacity=".8"/>)}
      {[["20,15","35,35"],["50,15","35,35"],["50,15","65,35"],["80,15","65,35"],["35,35","20,50"],["35,35","50,50"],["65,35","50,50"],["65,35","80,50"]].map((pair, i) => {
        const [a, b] = pair; const [x1,y1] = a.split(","); const [x2,y2] = b.split(",");
        return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke={`${c}40`} strokeWidth="1"/>;
      })}
    </svg>);
  return null;
}

