function OkruhMng8Panel() {
  const caseStudyMng8 = {
    title: "Pavel — generální ředitel českého výrobce zdravotnické techniky MediTech, 450 zaměstnanců",
    subtitle: "Identifikuj odpor ke změně a navrhni Change Management proces",
    scenario: "Pavel (50 let) vede 12 let MediTech, českou rodinnou firmu vyrábějící zdravotnickou techniku (dýchací přístroje, monitory). 450 zaměstnanců, 60% trhu v ČR, tržby 800 mil. Kč ročně. Firma má 40letou tradici, dvě generace rodiny.\n\nTrh se ale mění — konkurence (Philips, Dräger) zavedla AI diagnostiku, IoT připojení přístrojů, telemedicínu. MediTech to nemá. Pavel chce zavést digitální transformaci: nová firmware platforma, IoT cloud, AI software, partner channel přes integrátory. Investice 120 mil. Kč, projekt na 18 měsíců.\n\nOznámil to 4 měsíce zpátky na all-hands. Od té doby vzniká odpor. R&D ředitel (Karel, 58 let, ve firmě 25 let) říká: AI je hype, naše přístroje jsou nejlepší, vyrobíme nejlepší přístroj a klienti přijdou. 3 senior inženýři podepsali stížnost. Production manažer (Marek) tvrdí: výroba je optimalizovaná, IoT komplikuje servis. HR oddělení paniku, protože 30 % zaměstnanců nezná Python ani cloud.\n\nKupcovský odpor: ostatní bývalí kolegové (rodinní příslušníci) tlačí Pavla, aby zachoval tradici. Pavel ale ví, že bez digitální transformace firma za 5 let nedokáže konkurovat. Top investor (Jet Investments) hrozí, že stáhne kapitálovou účast, pokud nedojde k transformaci. Pavel zvažuje Kotterových 8 kroků, ale neví, kde začít.",
    signals: [
      { text: "AI je hype, naše přístroje jsou nejlepší, vyrobíme nejlepší přístroj a klienti přijdou", color: VSE.danger, reason: "Klasický odpor — komfortní zónou. Karel ignoruje signály trhu. Kotter krok 1: Vytvořit pocit naléhavosti chybí." },
      { text: "3 senior inženýři podepsali stížnost", color: VSE.warning, reason: "Organizovaný odpor — formalizovaný protest. Klasický signál, že Pavel přeskočil kroky 2-3 Kottera (koalice, vize)." },
      { text: "30 % zaměstnanců nezná Python ani cloud", color: VSE.warning, reason: "Skills gap = lock-in. Bariéra ke změně. Lewin: bez unfreeze (rekvalifikace) zaměstnanci sabotují." },
      { text: "ostatní bývalí kolegové (rodinní příslušníci) tlačí Pavla, aby zachoval tradici", color: VSE.danger, reason: "Pasti tradice — emocionální odpor. Klasický u rodinných firem. Senge: mental model lock-in." },
      { text: "Top investor (Jet Investments) hrozí, že stáhne kapitálovou účast", color: VSE.warning, reason: "Externí pressure burning platform — Kotter krok 1 zdola. Pavel může použít jako pocit naléhavosti." },
      { text: "Pavel zvažuje Kotterových 8 kroků, ale neví, kde začít", color: VSE.warning, reason: "Pavel oznámil změnu (krok 4) bez kroku 1-3. Klasická chyba — vize bez koalice + naléhavosti." },
    ],
    quiz1: {
      question: "Jaký je hlavní problém s tím, jak Pavel zavádí změnu?",
      options: [
        "Změna je špatná — měl by zachovat tradici",
        "Pavel přeskočil Kotterovy kroky 1-3 (naléhavost, koalice, vize) a rovnou oznámil změnu — proto narazil na odpor",
        "Firma je příliš stará na změnu — měla by být prodaná",
        "Investice je příliš velká — měla by se rozdělit",
      ],
      correct: 1,
    },
    quiz2: {
      question: "Co by Pavel měl udělat v dalších 6 měsících (Kotter + Lewin)?",
      options: [
        { text: "Vytvořit pocit naléhavosti (Kotter 1): prezentace konkurenčních dat (Philips/Dräger AI), trh data, investor pressure", correct: true, reason: "✓ Klasický krok 1 — burning platform. Bez něj zaměstnanci nevidí důvod změny. Senge: data driven storytelling." },
        { text: "Sestavit silnou koalici (Kotter 2): Karel + Marek + 2 mladší senior inženýři + 1 externí AI expert", correct: true, reason: "✓ Koalice musí zahrnovat OPONENTY (Karla, Marka), ne jen přívržence. Klasická chyba — koalice jen z příznivců nefunguje." },
        { text: "Propustit Karla a 3 stěžovatele — odstranit odpor", correct: false, reason: "✗ Ničí know-how + signál ostatním = sabotáž. Lepší: Karla začlenit do koalice, udělat z něj champion." },
        { text: "Formulovat společně s koalicí jasnou vizi (Kotter 3): jak bude MediTech vypadat za 3 roky po transformaci", correct: true, reason: "✓ Vize = obraz cílového stavu. Bez něj zaměstnanci nevědí kam jdou. Kotter: 1 minuta nestačí, musí být jasná." },
        { text: "Zavést rekvalifikační program (Python, cloud) pro 30 % zaměstnanců, kteří to neumí (Lewin Unfreeze)", correct: true, reason: "✓ Skills gap = bariéra. Lewin: bez unfreeze není change. Investice do lidí > investice do technologie." },
        { text: "Začít s pilotním projektem — 1 produktová řada s IoT, ne všechno najednou (Kotter 6: Krátkodobá vítězství)", correct: true, reason: "✓ Krátkodobá vítězství staví důvěru. Místo big bang 18měsíční projekt = série 6měsíčních milestones." },
        { text: "Zrušit transformaci a počkat, až generační výměna proběhne sama", correct: false, reason: "✗ Bez akce konkurence sebere trh za 2-3 roky. Bez transformace MediTech zaniká. Tradice je vzpomínka, ne strategie." },
      ],
    },
    summary: "<b>Pavel udělal klasickou chybu Change Managementu — oznámil změnu, ale neabsolvoval Kotterových kroků 1-3.</b> Bez naléhavosti, koalice a vize narazil na odpor.<br/><br/><b>Plán 6 měsíců (Kotter + Lewin):</b><br/>• <b>Měsíc 1:</b> Unfreeze — burning platform (konkurenční data), investor pressure jako naléhavost<br/>• <b>Měsíc 2:</b> Koalice (Karel jako champion, ne nepřítel) + sepsaná vize<br/>• <b>Měsíc 3-4:</b> Rekvalifikace (Python, cloud) pro 30 % týmu<br/>• <b>Měsíc 5-6:</b> Pilotní IoT projekt na 1 produktové řadě (krátkodobé vítězství)<br/><br/><b>Pro komisi:</b> Klasická Kotter-vs-Lewin lekce. Pavel zvolil Change Program (Kotter top-down), ale neporozumněl, že prvních 5 kroků je o LIDECH, ne o technologii. Senge: mental models jsou nejtěžší bariéra. Doporučení: zpomalit, vrátit se ke krokům 1-3, integrovat oponenty.",
  };

  return (<OkruhPanel subject="Management" subjectId="mng" number={8} title="Change Management" subtitle="Kotter / Lewin / Teorie U / Program vs Platform" color={VSE.ffu}
    questionText="Change management, modely, rozdíly, bariéry, metody a postupy, proč to potřebujeme."
    sloz={3} roz={3} freq={3}
    examStrategy={examStrategy8}
    studySections={studySections8} flashcards={flashcards8} quiz={quiz8}
    praxe={praxe8} examQuestions={examQuestions8} podcast={podcast8}
    caseStudy={caseStudyMng8} />);
}

