function OkruhMng9Panel() {
  const caseStudyMng9 = {
    title: "Marek — CEO B2B SaaS firmy DataFlow, 80 lidí",
    subtitle: "Identifikuj management model na Birkinshaw matici a navrhni inovaci managementu",
    scenario: "Marek (37 let) vede 4 roky DataFlow, B2B SaaS pro data integrace (typu Stitch/Fivetran). Firma má 80 zaměstnanců v Praze a Brně, MRR 4 mil. EUR, 200 klientů v EU. Růst 30 % ročně, ziskovost 12 %.\n\nManagement model DataFlow: cíle jsou jasně specifikované (kvartální OKR, roční ARR target), rozhodování centralizované (Marek + 4 VPs), motivace přes plat + stock options + roční bonus podle splnění OKR, koordinace přes Slack + týdenní all-hands. Klasický Planning model (jistá cesta + jasné cíle) v Birkinshaw matici.\n\nProblém: trh se mění rychle. Konkurence (Airbyte, Hightouch) přichází s open-source modely, AI features, novými UX paradigmaty. Inovace v DataFlow ale stagnují — vývoj nového feature trvá 8 měsíců, OKR systém penalizuje experimentování (když vývojář selže s pilotem, jeho OKR je červené), nikdo nechce zkoušet nové věci. Marek si všiml, že top inženýři odcházejí (3 senior eng za poslední rok). Stack jeho R&D týmu je technicky výborný, ale management model brzdí inovace.\n\nMarek čte Hamela a Birkinshawa a uvažuje: produkt je dobrý, ale management model je z 90. let. Inovace managementu = KV (konkurenční výhoda) — kterou ostatní těžko zkopírují. Trh tlačí, top investor Sequoia chce vidět innovation roadmap.",
    signals: [
      { text: "cíle jsou jasně specifikované (kvartální OKR, roční ARR target), rozhodování centralizované", color: VSE.warning, reason: "Klasický Planning model (Birkinshaw): tight ENDS + tight MEANS. Vhodný pro stabilní trh, ne pro inovační prostředí." },
      { text: "OKR systém penalizuje experimentování (když vývojář selže s pilotem, jeho OKR je červené)", color: VSE.danger, reason: "Klasický anti-vzor — OKR jako kontrola místo aspirace. Google původní OKR měl 70% splnění jako úspěch (stretch goals)." },
      { text: "vývoj nového feature trvá 8 měsíců", color: VSE.danger, reason: "Time-to-market signál stagnace. Konkurence rychlejší — Birkinshaw: tight management zabíjí innovation velocity." },
      { text: "top inženýři odcházejí (3 senior eng za poslední rok)", color: VSE.danger, reason: "Talent drain — inženýři chtějí prostor, ne kontrolu. Senge: učící se organizace přitahuje talent." },
      { text: "produkt je dobrý, ale management model je z 90. let", color: VSE.warning, reason: "Marek pochopil Hamela — produktová KV je dočasná, management innovation je dlouhodobá KV." },
      { text: "Inovace managementu = KV (konkurenční výhoda) — kterou ostatní těžko zkopírují", color: VSE.success, reason: "Klasický Hamel — inovace managementu je nejhlubší. Produkt se dá zkopírovat za rok, management innovation roky." },
    ],
    quiz1: {
      question: "Jaký management model DataFlow používá podle Birkinshaw matice?",
      options: [
        "Quest model (loose ENDS + loose MEANS) — jako Google v inovacích",
        "Planning model (tight ENDS + tight MEANS) — klasická korporace 20. století",
        "Discovery model (loose ENDS + loose MEANS) — startup mode",
        "Science model (loose ENDS + tight MEANS) — akademický přístup",
      ],
      correct: 1,
    },
    quiz2: {
      question: "Jaké inovace managementu by Marek měl zavést?",
      options: [
        { text: "Pro inovační týmy přejít na Discovery model — loose ENDS (experimentování) + loose MEANS (žádný OKR)", correct: true, reason: "✓ Birkinshaw: různé typy práce vyžadují různé modely. Innovation = Discovery. Core business zůstane Planning." },
        { text: "Změnit OKR z kontroly na aspiraci — 70% splnění = úspěch (Google originál), nepenalizovat experimenty", correct: true, reason: "✓ Klasický fix OKR. Stretch goals neznamená 100% splnění. Selhání = učení, ne známka." },
        { text: "Zavést 20% rule (Google) nebo hackathony — strukturovaný prostor pro experimenty", correct: true, reason: "✓ Strukturální mechanismus innovation. Google Gmail, AdSense vznikly takto. Levné, vysoký ROI." },
        { text: "Centralizovat ještě víc — Marek sám rozhoduje o všech inovacích", correct: false, reason: "✗ Opak řešení. Centralizace = bottleneck, ne innovation. Birkinshaw: distribute decision rights." },
        { text: "Najmout COO, který bude řídit operations, a sám se soustředit na innovation strategy", correct: true, reason: "✓ Roli CEO rozdělit — Marek innovation + vision, COO ops. Klasický pattern při 80+ lidech." },
        { text: "Zavést Innovation Council s autonomními rozhodovacími pravomocemi do 500 tis. Kč", correct: true, reason: "✓ Distribuovaná decision rights pro innovation. Rychlé experimentování bez centrální schválení." },
        { text: "Outsourcovat innovation — najmout externí inovační agenturu", correct: false, reason: "✗ Klasický anti-vzor. Innovation musí vycházet z firmy, ne agentura. Hamel: inovace managementu je interní proces." },
      ],
    },
    summary: "<b>DataFlow je klasický Planning model v Birkinshaw matici — tight ENDS + tight MEANS.</b> Funguje pro stabilní trh, ale brzdí inovace v dynamickém SaaS prostředí.<br/><br/><b>Hybridní inovace managementu:</b><br/>• <b>Core business</b> (existing product, sales): Planning model (OKR, hierarchie, kontrola)<br/>• <b>Innovation lab</b> (nové features, AI experimenty): Discovery model (volný experiment, no OKR penalty)<br/>• <b>R&D týmy</b>: Quest model (loose ENDS, tight MEANS — vize jasná, cesta flexibilní)<br/><br/><b>Pro komisi:</b> Hamel přesně říká — produktová KV je dočasná (rok), management innovation je dlouhodobá (5-10 let). Konkurence zkopíruje feature, ale neumí zkopírovat management model. Birkinshaw 4 modely: firma musí zvolit podle typu práce, ne podle ideologie.",
  };

  return (<OkruhPanel subject="Management" subjectId="mng" number={9} title="Trendy v managementu + Birkinshaw modely" subtitle="4 modely / MEANS × ENDS / Inovace managementu = KV" color={VSE.ffu}
    questionText="Trendy v managementu, management modely (Birkinshaw), vztáhnout na případovku, inovace managementu, proč přinášejí KV."
    sloz={3} roz={3} freq={3}
    examStrategy={examStrategy9}
    studySections={studySections9} flashcards={flashcards9} quiz={quiz9}
    praxe={praxe9} examQuestions={examQuestions9} podcast={podcast9}
    caseStudy={caseStudyMng9} />);
}

