              <div style={{ width: 22, height: 22, borderRadius: 11, background: s.color, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, fontWeight: 800, fontFamily: fontMono }}>{s.num}</div>
