  const flashcardsStr9 = [
    { term: "Strategie inovací", def: "Systematický přístup k tvorbě a uvedení inovací. Bez inovací firma stagnuje a umírá (Schumpeter creative destruction).", tag: "POJEM" },
    { term: "Schumpeter 5 typů inovací", def: "Produktová / Procesní / Organizační / Tržní / Dodavatelská. 1934.", tag: "TYPY" },
    { term: "Produktová inovace", def: "Nový nebo zlepšený produkt. iPhone 2007, Tesla EV.", tag: "TYPY" },
    { term: "Procesní inovace", def: "Nový výrobní/operating proces. Toyota TPS, Ford montážní linka.", tag: "TYPY" },
    { term: "Organizační inovace", def: "Nová organizační struktura. Spotify squads, Holacracy.", tag: "TYPY" },
    { term: "Tržní inovace", def: "Vstup na nový trh. Coca-Cola do nové geografie, Tesla do Číny 2019.", tag: "TYPY" },
    { term: "Dodavatelská inovace", def: "Nové zdroje, suroviny. Sustainable materials (Patagonia), nové battery chemistry (Tesla 4680).", tag: "TYPY" },
    { term: "Inkrementální × Radikální", def: "Inkrementální = malé zlepšení (iPhone YoY). Radikální = breakthrough (první iPhone 2007).", tag: "TYPY" },
    { term: "Closed × Open innovation (Chesbrough 2003)", def: "Closed = in-house, NIH syndrom. Open = external partnerships (P&G Connect+Develop).", tag: "TYPY" },
    { term: "Utterback-Abernathy model (1975)", def: "3 fáze průmyslu: Fluid (early, product innovation) / Transitional (dominant design) / Specific (mature, process innovation).", tag: "MODEL" },
    { term: "Fluid phase", def: "Early industry. Many product variations. High product innovation. Many small players. Smartphones 2007-2010.", tag: "MODEL" },
    { term: "Transitional phase", def: "Dominant design emerges. Industry consolidation. Process innovation increases. Smartphones 2011-2015.", tag: "MODEL" },
    { term: "Specific phase", def: "Mature industry. Process innovation dominant. Cost efficiency. Few large players. Smartphones 2018+.", tag: "MODEL" },
    { term: "Technology Push × Market Pull", def: "Push = R&D-led (Apple iPad, Tesla). Pull = customer needs-led (P&G, Toyota Camry).", tag: "STRATEGY" },
    { term: "Exploitation × Exploration (March 1991)", def: "Klíčový paradox. Exploitation = vylepšování existing (Kaizen). Exploration = investice do nového (R&D).", tag: "PARADOX" },
    { term: "Innovator's Dilemma (Christensen 1997)", def: "Established firms succeed na exploitation, fail na exploration. Kodak, BlackBerry, Blockbuster classic examples.", tag: "PARADOX" },
    { term: "Sustaining × Disruptive innovations", def: "Sustaining = improvements pro existing customers. Disruptive = nové trhy/segmenty, eventually overtake incumbents.", tag: "PARADOX" },
    { term: "Christensen řešení", def: "Create separate org units for exploration. Skunkworks, separate P&L, different culture. IBM Watson Lab, Google X.", tag: "PARADOX" },
    { term: "Blue Ocean Strategy (Kim+Mauborgne 2005)", def: "Modrý oceán = new uncontested market. Rudý oceán = existing crowded market. Create new demand.", tag: "OCEÁN" },
    { term: "Rudý oceán", def: "Existing market space, bloody competition. Defined boundaries. Zero-sum. Walmart vs Target, Coca-Cola vs Pepsi.", tag: "OCEÁN" },
    { term: "Modrý oceán", def: "New uncontested market space. Differentiation + low cost simultaneously. Cirque du Soleil, Tesla early, Nintendo Wii.", tag: "OCEÁN" },
    { term: "Hodnotová inovace (Value Innovation)", def: "Foundation Blue Ocean. Differentiation AND low cost simultaneously. ERRC Grid framework.", tag: "OCEÁN" },
    { term: "ERRC Grid (4 actions)", def: "Eliminate / Reduce / Raise / Create. Framework pro Modrý oceán. Cirque du Soleil classic.", tag: "OCEÁN" },
    { term: "Cirque du Soleil příklad", def: "Eliminate stars+animals. Reduce thrill. Raise venue+music. Create theme+artistic fusion. Circus + theater hybrid.", tag: "OCEÁN" },
    { term: "Brzdné síly inovací", def: "Bariéry implementace. 80 % inovací selže. Organizační/finanční/kulturní/lidské/externí barriers.", tag: "BRZDA" },
    { term: "NIH syndrom", def: "Not Invented Here. Reject external ideas, only in-house. Klasický closed innovation problem.", tag: "BRZDA" },
    { term: "Chasm (Geoffrey Moore 1991)", def: "Customer adoption gap between early adopters a early majority. Killer pro tech innovations. Google Glass = nepřekonal.", tag: "BRZDA" },
    { term: "Překonání brzdných sil", def: "Leadership commitment + dedicated budget + separate units + intrapreneurs + embrace failure + open innovation + cultural change.", tag: "BRZDA" },
    { term: "Schumpeter creative destruction", def: "Inovace destruují existing industries, vytváří nové. Klíč ekonomického růstu. Long waves of economic cycles.", tag: "POJEM" },
    { term: "Innovation funnel", def: "Many ideas → few prototypes → fewer products → 1-2 successes. Stage-Gate proces filtration.", tag: "POJEM" },
    { term: "Intrapreneurs (Pinchot 1985)", def: "Internal entrepreneurs. Innovate inside existing firms. Google 20 % time, 3M 15 % time, Microsoft Garage.", tag: "BRZDA" },
  ];

