          <text x="380" y="36" textAnchor="middle" fontFamily={fontMono} fontSize="9.5" fill="var(--text-muted)" fontStyle="italic">leva = infrastruktura (OUT) | stred = hodnota | prava = trh, penize IN</text>
          {/* Row 1 — top 7 blocks */}
